#!/usr/bin/env python3
import subprocess
import sys

def main():
    try:
        result = subprocess.run(
            ['nvidia-smi', '--query-gpu=utilization.gpu,memory.used,memory.total,temperature.gpu', '--format=csv,noheader,nounits'],
            capture_output=True, text=True, check=True
        )
        line = result.stdout.strip()
        if not line:
            raise RuntimeError("No GPU data returned")
        values = [int(x) for x in line.split(',')]
        gpu_data = {
            "utilization_gpu": values[0],
            "memory_used_mb": values[1],
            "memory_total_mb": values[2],
            "temperature_gpu_c": values[3]
        }
        print(gpu_data)
    except (subprocess.CalledProcessError, FileNotFoundError):
        # Fallback: try rocm-smi or /sys/class/drm
        print("{'error': 'NVIDIA GPU not found, fallback not implemented'}", file=sys.stderr)
        sys.exit(1)

if __name__ == '__main__':
    main()

